        /// <summary>
        /// 注册 OpenCvSharp 原生库路径
        /// </summary>
        static void RegisterOpenCvSharpNativePath()
        {
            string baseDir = AppDomain.CurrentDomain.BaseDirectory;

            // ✅ 根据你的实际路径修改这里
            // 如果 DLL 在 bin/Debug/dll/x64/
            string nativePath = Path.Combine(baseDir, "dll", "x86");

            // 如果 DLL 在 bin/Debug/x64/（另一种可能）
            // string nativePath = Path.Combine(baseDir, "x64");

            if (Directory.Exists(nativePath))
            {
                // 将路径添加到 DLL 搜索目录
                AddDllDirectory(nativePath);

                Debug.WriteLine($"✅ 已注册 OpenCvSharp 原生库路径: {nativePath}");

                // 验证关键文件
                string externDll = Path.Combine(nativePath, "OpenCvSharpExtern.dll");
                if (File.Exists(externDll))
                {
                    Debug.WriteLine($"✅ 找到核心库: OpenCvSharpExtern.dll");
                }
                else
                {
                    Debug.WriteLine($"❌ 警告: 未找到 OpenCvSharpExtern.dll");
                }
            }
            else
            {
                Debug.WriteLine($"❌ 错误: 原生库路径不存在: {nativePath}");
            }
        }

        [DllImport("kernel32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
        private static extern bool AddDllDirectory(string lpPathName);

        private static void ActivateExistingInstance()
        {
            try
            {
                // 查找窗口句柄（lpWindowName需与主窗体Title一致）
                IntPtr hwnd = FindWindow(null, "UCM_Tools"); // 确保MainForm.Text = "UCM_Tools"

                if (hwnd != IntPtr.Zero)
                {
                    // 如果窗口最小化，先还原
                    ShowWindow(hwnd, SW_RESTORE);

                    // 将窗口置于前台
                    SetForegroundWindow(hwnd);
                }
                else
                {
                    // 备用方案：通过进程名查找（更健壮）
                    var currentProcess = System.Diagnostics.Process.GetCurrentProcess();
                    var processes = System.Diagnostics.Process.GetProcessesByName(currentProcess.ProcessName);
                    foreach (var process in processes)
                    {
                        if (process.Id != currentProcess.Id)
                        {
                            hwnd = process.MainWindowHandle;
                            if (hwnd != IntPtr.Zero)
                            {
                                ShowWindow(hwnd, SW_RESTORE);
                                SetForegroundWindow(hwnd);
                                break;
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Log.Error("激活已有实例失败: " + ex.Message);
            }
        }
        private static void CurrentDomain_UnhandledException(object sender, UnhandledExceptionEventArgs e)
        {
            Log.Error("CurrentDomain_UnhandledException:" + (e.ExceptionObject as Exception));
        }
        // 导入Windows API
        [DllImport("user32.dll")]
        static extern bool SetForegroundWindow(IntPtr hWnd);

        [DllImport("user32.dll")]
        static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);

        [DllImport("user32.dll")]
        static extern IntPtr FindWindow(string lpClassName, string lpWindowName);

        [DllImport("user32.dll")]
        static extern bool IsIconic(IntPtr hWnd); // 判断窗口是否最小化

        const int SW_RESTORE = 9; // 还原窗口
        [DllImport("kernel32.dll", CharSet = CharSet.Auto, SetLastError = true)]
        public static extern IntPtr GetModuleHandle(string lpModuleName);
        [DllImport("kernel32.dll", CharSet = CharSet.Auto)]
        public static extern uint GetModuleFileName(IntPtr hModule, StringBuilder lpFilename, uint nSize);
    }
